CREATE TRIGGER trg_decks_insert_no_mixed_content
BEFORE INSERT ON decks
WHEN NEW.parent_id IS NOT NULL AND EXISTS (
  SELECT 1 FROM flashcards
  WHERE deck_id = NEW.parent_id AND deleted_at IS NULL
)
BEGIN
  SELECT RAISE(ABORT, 'deck-mixed-content');
END;

CREATE TRIGGER trg_flashcards_insert_no_mixed_content
BEFORE INSERT ON flashcards
WHEN EXISTS (SELECT 1 FROM decks WHERE parent_id = NEW.deck_id)
BEGIN
  SELECT RAISE(ABORT, 'deck-mixed-content');
END;

CREATE TRIGGER trg_decks_insert_no_self_parent
BEFORE INSERT ON decks
WHEN NEW.parent_id IS NOT NULL AND NEW.parent_id = NEW.id
BEGIN
  SELECT RAISE(ABORT, 'deck-cycle');
END;

CREATE TRIGGER trg_decks_move_no_cycle
BEFORE UPDATE OF parent_id ON decks
WHEN NEW.parent_id IS NOT NULL AND NEW.parent_id IS NOT OLD.parent_id AND (
  NEW.parent_id = NEW.id OR EXISTS (
    WITH RECURSIVE descendants (id) AS (
      SELECT id FROM decks WHERE parent_id = NEW.id
      UNION ALL
      SELECT d.id FROM decks d
        INNER JOIN descendants s ON d.parent_id = s.id
    )
    SELECT 1 FROM descendants WHERE id = NEW.parent_id
  )
)
BEGIN
  SELECT RAISE(ABORT, 'deck-cycle');
END;

CREATE TRIGGER trg_decks_insert_same_pair
BEFORE INSERT ON decks
WHEN NEW.parent_id IS NOT NULL
  AND EXISTS (SELECT 1 FROM decks WHERE id = NEW.parent_id)
  AND (
    SELECT language_pair_id FROM decks WHERE id = NEW.parent_id
  ) IS NOT NEW.language_pair_id
BEGIN
  SELECT RAISE(ABORT, 'deck-pair-mismatch');
END;

CREATE TRIGGER trg_decks_move_same_pair
BEFORE UPDATE OF parent_id ON decks
WHEN NEW.parent_id IS NOT NULL
  AND NEW.parent_id IS NOT OLD.parent_id
  AND (
    SELECT language_pair_id FROM decks WHERE id = NEW.parent_id
  ) IS NOT NEW.language_pair_id
BEGIN
  SELECT RAISE(ABORT, 'deck-pair-mismatch');
END;

CREATE UNIQUE INDEX idx_decks_root_sibling_name ON decks (
  language_pair_id,
  normalized_name
) WHERE parent_id IS NULL;

CREATE UNIQUE INDEX idx_decks_child_sibling_name ON decks (
  parent_id,
  normalized_name
) WHERE parent_id IS NOT NULL;
